13: // Actions keeps track of action declarations accessible to the context.
14: // It is used to plan and execute actions in the context of a Terraform configuration.
15: type Actions struct {
16: 	// Must hold this lock when accessing all fields after this one.
17: 	mu sync.Mutex
18: 
19: 	actionInstances        addrs.Map[addrs.AbsActionInstance, ActionData]
20: 	partialExpandedActions addrs.Map[addrs.PartialExpandedAction, ActionData]
21: }
