23: func NewActions() *Actions {
24: 	return &Actions{
25: 		actionInstances:        addrs.MakeMap[addrs.AbsActionInstance, ActionData](),
26: 		partialExpandedActions: addrs.MakeMap[addrs.PartialExpandedAction, ActionData](),
27: 	}
28: }
