35: func (a *Actions) AddActionInstance(addr addrs.AbsActionInstance, configValue cty.Value, providerAddr addrs.AbsProviderConfig) {
36: 	a.mu.Lock()
37: 	defer a.mu.Unlock()
38: 
39: 	if a.actionInstances.Has(addr) {
40: 		panic("action instance already exists: " + addr.String())
41: 	}
42: 
43: 	a.actionInstances.Put(addr, ActionData{
44: 		ConfigValue:  configValue,
45: 		ProviderAddr: providerAddr,
46: 	})
47: }
